// web简单的ua爬虫过滤
import { IInitParam } from '../../../types/types'

export default class Spider {
  spiderBot: string[]
  constructor() {
    this.spiderBot = [
      'Baiduspider',
      'googlebot',
      '360Spider',
      'haosouspider',
      'YoudaoBot',
      'Sogou News Spider',
      'Yisouspider',
      'Googlebot',
      'Headless',
      'Applebot',
      'Bingbot',
      'PetalBot',
    ]
  }
  checkSpider(config: IInitParam) {
    if (!config.enable_spider) return false;
    const ua = window.navigator.userAgent;
    if (!ua) return true;
    let isSpider: boolean = false;
    this.spiderBot.forEach((item: string) => {
      if (ua.indexOf(item) !== -1) {
        isSpider = true
      }
    })
    return isSpider;
  }
}